import { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import Shell from "../components/Shell";
import { useCurrency } from "../CurrencyContext";
import { getUserGroups, getUserTransactions } from "../api";

function Donut({ owe, owed }) {
  const { fmt } = useCurrency();
  const C = 502.4; // 2*PI*80

  const total = owe + owed;
  const oweRatio = total > 0 ? owe / total : 0;
  const owedRatio = total > 0 ? owed / total : 0;

  // Use dynamic segments based on owe/owed if they exist
  // If total is 0, show a single empty segment
  const segs = total > 0 ? [
    { v: oweRatio, color: "#ef4444", label: "You Owe" },
    { v: owedRatio, color: "#10b981", label: "You are Owed" }
  ].filter(s => s.v > 0) : [
    { v: 1, color: "#e5e7eb", label: "No activity" }
  ];

  let off = 0;
  return (
    <div className="d-flex flex-column align-items-center">
      <svg viewBox="0 0 200 200" width="200" height="200">
        <circle cx="100" cy="100" r="80" fill="none" stroke="#f1f5f9" strokeWidth="30" />
        {segs.map((s, i) => {
          const dash = s.v * C;
          const node = (
            <circle key={i} cx="100" cy="100" r="80" fill="none"
              stroke={s.color} strokeWidth="30"
              strokeDasharray={`${dash} ${C}`}
              strokeDashoffset={-off}
              transform="rotate(-90 100 100)" />
          );
          off += dash;
          return node;
        })}
        <text x="100" y="95" textAnchor="middle" fontSize="18" fontWeight="700" fill="currentColor">{fmt(total)}</text>
        <text x="100" y="115" textAnchor="middle" fontSize="11" fill="#64748b">TOTAL INVOLVED</text>
      </svg>
      {total > 0 && (
        <div className="mt-3 d-flex gap-3 text-muted small fw-bold">
          {segs.map(s => (
            <span key={s.label}><span style={{display: 'inline-block', width: 8, height: 8, background: s.color, borderRadius: '50%', marginRight: 4}}></span>{s.label} {Math.round(s.v * 100)}%</span>
          ))}
        </div>
      )}
    </div>
  );
}

export default function Dashboard() {
  const [groups, setGroups] = useState([]);
  const [owe, setOwe] = useState(0);
  const [owed, setOwed] = useState(0);
  const { fmt } = useCurrency();
  const nav = useNavigate();
  const currentUser = JSON.parse(localStorage.getItem("currentUser"));

  useEffect(() => {
    if (!currentUser) {
      nav("/login");
      return;
    }

    async function fetchData() {
      try {
        const fetchedGroups = await getUserGroups(currentUser._id);
        setGroups(fetchedGroups);

        const fetchedTransactions = await getUserTransactions(currentUser._id);
        let tempOwe = 0;
        let tempOwed = 0;

        fetchedTransactions.forEach(t => {
          if (!t.isSettled) {
            if (t.fromUser._id === currentUser._id) {
              tempOwe += t.amount;
            } else if (t.toUser._id === currentUser._id) {
              tempOwed += t.amount;
            }
          }
        });

        setOwe(tempOwe);
        setOwed(tempOwed);
      } catch (err) {
        console.error("Failed to fetch dashboard data", err);
      }
    }

    fetchData();
  }, [currentUser, nav]);

  if (!currentUser) return null;

  return (
    <Shell>
      <div className="page">
        <h1 className="page-title">Hello {currentUser.name}!</h1>
        <p className="page-sub">Ready to harmonize your shared finances today?</p>

        <div className="row g-4 mb-4">
          <div className="col-md-6">
            <div className="card-soft">
              <div className="label-muted mb-2">↗️ Total you owe</div>
              <div className="amount amount-red mb-3">{fmt(owe)}</div>
              <div className="d-flex gap-2 mt-3">
                <button className="btn-green">Settle Now</button>
              </div>
            </div>
          </div>
          <div className="col-md-6">
            <div className="card-purple h-100">
              <div className="muted mb-2">Total you are owed</div>
              <div className="amount-lg mb-4">{fmt(owed)}</div>
              <div className="muted" style={{ fontSize: 12, letterSpacing: 1 }}>KEEP IT UP!</div>
              <div className="d-flex align-items-center gap-2 mt-2">
                <div className="member-dot" style={{ background: "#10b981", borderColor: "transparent" }}>+</div>
                <div>
                  <div style={{ fontWeight: 600 }}>Active</div>
                  <div className="muted small">Syncing...</div>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="row g-4">
          <div className="col-md-7">
            <div className="card-soft">
              <div className="d-flex justify-content-between align-items-center mb-4">
                <h3 style={{ fontWeight: 700, margin: 0 }}>Expense Analytics</h3>
                <span className="pill pill-purple">Realtime</span>
              </div>
              <div className="d-flex flex-column justify-content-center align-items-center gap-4 mt-4">
                <div className="text-center"><Donut owe={owe} owed={owed} /></div>
              </div>
            </div>
          </div>
          <div className="col-md-5">
            <div className="d-flex justify-content-between align-items-center mb-3">
              <h3 style={{ fontWeight: 700, margin: 0 }}>Your Groups</h3>
              <Link to="/create-group" style={{ color: "var(--primary)", fontWeight: 600, textDecoration: "none" }}>+ New Group</Link>
            </div>
            {groups.length === 0 ? <p className="text-muted">No groups yet.</p> : groups.slice(0, 4).map((g) => (
              <Link to={`/groups/${g._id}`} key={g._id} className="group-card">
                <div className="card-soft mb-3">
                  <div className="d-flex align-items-center justify-content-between">
                    <div className="d-flex align-items-center gap-3">
                      <div className="group-icon" style={{ marginBottom: 0 }}>{g.icon || "📁"}</div>
                      <div>
                        <div style={{ fontWeight: 600, fontSize: 16 }}>{g.name}</div>
                        <div className="text-muted small">{g.members.length} members</div>
                      </div>
                    </div>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        </div>
      </div>
    </Shell>
  );
}
